4201 Instruction *InstCombinerImpl::foldICmpIntrinsicWithConstant(ICmpInst &Cmp,
4202                                                              IntrinsicInst *II,
4203                                                              const APInt &C) {
4204   ICmpInst::Predicate Pred = Cmp.getPredicate();
4205 
4206   // Handle folds that apply for any kind of icmp.
4207   switch (II->getIntrinsicID()) {
4208   default:
4209     break;
4210   case Intrinsic::uadd_sat:
4211   case Intrinsic::usub_sat:
4212     if (auto *Folded = foldICmpUSubSatOrUAddSatWithConstant(
4213             Pred, cast<SaturatingInst>(II), C, Builder))
4214       return Folded;
4215     break;
4216   case Intrinsic::ctpop: {
4217     const SimplifyQuery Q = SQ.getWithInstruction(&Cmp);
4218     if (Instruction *R = foldCtpopPow2Test(Cmp, II, C, Builder, Q))
4219       return R;
4220   } break;
4221   case Intrinsic::scmp:
4222   case Intrinsic::ucmp:
4223     if (auto *Folded = foldICmpOfCmpIntrinsicWithConstant(Pred, II, C, Builder))
4224       return Folded;
4225     break;
4226   }
4227 
4228   if (Cmp.isEquality())
4229     return foldICmpEqIntrinsicWithConstant(Cmp, II, C);
4230 
4231   Type *Ty = II->getType();
4232   unsigned BitWidth = C.getBitWidth();
4233   switch (II->getIntrinsicID()) {
4234   case Intrinsic::ctpop: {
4235     // (ctpop X > BitWidth - 1) --> X == -1
4236     Value *X = II->getArgOperand(0);
4237     if (C == BitWidth - 1 && Pred == ICmpInst::ICMP_UGT)
4238       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_EQ, X,
4239                              ConstantInt::getAllOnesValue(Ty));
4240     // (ctpop X < BitWidth) --> X != -1
4241     if (C == BitWidth && Pred == ICmpInst::ICMP_ULT)
4242       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_NE, X,
4243                              ConstantInt::getAllOnesValue(Ty));
4244     break;
4245   }
4246   case Intrinsic::ctlz: {
4247     // ctlz(0bXXXXXXXX) > 3 -> 0bXXXXXXXX < 0b00010000
4248     if (Pred == ICmpInst::ICMP_UGT && C.ult(BitWidth)) {
4249       unsigned Num = C.getLimitedValue();
4250       APInt Limit = APInt::getOneBitSet(BitWidth, BitWidth - Num - 1);
4251       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_ULT,
4252                              II->getArgOperand(0), ConstantInt::get(Ty, Limit));
4253     }
4254 
4255     // ctlz(0bXXXXXXXX) < 3 -> 0bXXXXXXXX > 0b00011111
4256     if (Pred == ICmpInst::ICMP_ULT && C.uge(1) && C.ule(BitWidth)) {
4257       unsigned Num = C.getLimitedValue();
4258       APInt Limit = APInt::getLowBitsSet(BitWidth, BitWidth - Num);
4259       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_UGT,
4260                              II->getArgOperand(0), ConstantInt::get(Ty, Limit));
4261     }
4262     break;
4263   }
4264   case Intrinsic::cttz: {
4265     // Limit to one use to ensure we don't increase instruction count.
4266     if (!II->hasOneUse())
4267       return nullptr;
4268 
4269     // cttz(0bXXXXXXXX) > 3 -> 0bXXXXXXXX & 0b00001111 == 0
4270     if (Pred == ICmpInst::ICMP_UGT && C.ult(BitWidth)) {
4271       APInt Mask = APInt::getLowBitsSet(BitWidth, C.getLimitedValue() + 1);
4272       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_EQ,
4273                              Builder.CreateAnd(II->getArgOperand(0), Mask),
4274                              ConstantInt::getNullValue(Ty));
4275     }
4276 
4277     // cttz(0bXXXXXXXX) < 3 -> 0bXXXXXXXX & 0b00000111 != 0
4278     if (Pred == ICmpInst::ICMP_ULT && C.uge(1) && C.ule(BitWidth)) {
4279       APInt Mask = APInt::getLowBitsSet(BitWidth, C.getLimitedValue());
4280       return CmpInst::Create(Instruction::ICmp, ICmpInst::ICMP_NE,
4281                              Builder.CreateAnd(II->getArgOperand(0), Mask),
4282                              ConstantInt::getNullValue(Ty));
4283     }
4284     break;
4285   }
4286   case Intrinsic::ssub_sat:
4287     // ssub.sat(a, b) spred 0 -> a spred b
4288     //
4289     // Note this doesn't work for ssub.sat.i1 because ssub.sat.i1 0, -1 = 0
4290     // (because 1 saturates to 0).  Just skip the optimization for i1.
4291     if (ICmpInst::isSigned(Pred) && C.getBitWidth() > 1) {
4292       if (C.isZero())
4293         return new ICmpInst(Pred, II->getArgOperand(0), II->getArgOperand(1));
4294       // X s<= 0 is cannonicalized to X s< 1
4295       if (Pred == ICmpInst::ICMP_SLT && C.isOne())
4296         return new ICmpInst(ICmpInst::ICMP_SLE, II->getArgOperand(0),
4297                             II->getArgOperand(1));
4298       // X s>= 0 is cannonicalized to X s> -1
4299       if (Pred == ICmpInst::ICMP_SGT && C.isAllOnes())
4300         return new ICmpInst(ICmpInst::ICMP_SGE, II->getArgOperand(0),
4301                             II->getArgOperand(1));
4302     }
4303     break;
4304   case Intrinsic::abs: {
4305     if (!II->hasOneUse())
4306       return nullptr;
4307 
4308     Value *X = II->getArgOperand(0);
4309     bool IsIntMinPoison =
4310         cast<ConstantInt>(II->getArgOperand(1))->getValue().isOne();
4311 
4312     // If C >= 0:
4313     // abs(X) u> C --> X + C u> 2 * C
4314     if (Pred == CmpInst::ICMP_UGT && C.isNonNegative()) {
4315       return new ICmpInst(ICmpInst::ICMP_UGT,
4316                           Builder.CreateAdd(X, ConstantInt::get(Ty, C)),
4317                           ConstantInt::get(Ty, 2 * C));
4318     }
4319 
4320     // If abs(INT_MIN) is poison and C >= 1:
4321     // abs(X) u< C --> X + (C - 1) u<= 2 * (C - 1)
4322     if (IsIntMinPoison && Pred == CmpInst::ICMP_ULT && C.sge(1)) {
4323       return new ICmpInst(ICmpInst::ICMP_ULE,
4324                           Builder.CreateAdd(X, ConstantInt::get(Ty, C - 1)),
4325                           ConstantInt::get(Ty, 2 * (C - 1)));
4326     }
4327 
4328     break;
4329   }
4330   default:
4331     break;
4332   }
4333 
4334   return nullptr;
4335 }
