4337 /// Handle icmp with constant (but not simple integer constant) RHS.
4338 Instruction *InstCombinerImpl::foldICmpInstWithConstantNotInt(ICmpInst &I) {
4339   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
4340   Constant *RHSC = dyn_cast<Constant>(Op1);
4341   Instruction *LHSI = dyn_cast<Instruction>(Op0);
4342   if (!RHSC || !LHSI)
4343     return nullptr;
4344 
4345   switch (LHSI->getOpcode()) {
4346   case Instruction::IntToPtr:
4347     // icmp pred inttoptr(X), null -> icmp pred X, 0
4348     if (RHSC->isNullValue() &&
4349         DL.getIntPtrType(RHSC->getType()) == LHSI->getOperand(0)->getType())
4350       return new ICmpInst(
4351           I.getPredicate(), LHSI->getOperand(0),
4352           Constant::getNullValue(LHSI->getOperand(0)->getType()));
4353     break;
4354 
4355   case Instruction::Load:
4356     // Try to optimize things like "A[i] > 4" to index computations.
4357     if (GetElementPtrInst *GEP =
4358             dyn_cast<GetElementPtrInst>(LHSI->getOperand(0)))
4359       if (Instruction *Res =
4360               foldCmpLoadFromIndexedGlobal(cast<LoadInst>(LHSI), GEP, I))
4361         return Res;
4362     break;
4363   }
4364 
4365   return nullptr;
4366 }
