3612 /// Fold an icmp equality instruction with binary operator LHS and constant RHS:
3613 /// icmp eq/ne BO, C.
3614 Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
3615     ICmpInst &Cmp, BinaryOperator *BO, const APInt &C) {
3616   // TODO: Some of these folds could work with arbitrary constants, but this
3617   // function is limited to scalar and vector splat constants.
3618   if (!Cmp.isEquality())
3619     return nullptr;
