3625 
3626   switch (BO->getOpcode()) {
3627   case Instruction::SRem:
3628     // If we have a signed (X % (2^c)) == 0, turn it into an unsigned one.
3629     if (C.isZero() && BO->hasOneUse()) {
3630       const APInt *BOC;
3631       if (match(BOp1, m_APInt(BOC)) && BOC->sgt(1) && BOC->isPowerOf2()) {
3632         Value *NewRem = Builder.CreateURem(BOp0, BOp1, BO->getName());
3633         return new ICmpInst(Pred, NewRem,
3634                             Constant::getNullValue(BO->getType()));
3635       }
3636     }
3637     break;
3638   case Instruction::Add: {
3639     // (A + C2) == C --> A == (C - C2)
3640     // (A + C2) != C --> A != (C - C2)
3641     // TODO: Remove the one-use limitation? See discussion in D58633.
3642     if (Constant *C2 = dyn_cast<Constant>(BOp1)) {
3643       if (BO->hasOneUse())
3644         return new ICmpInst(Pred, BOp0, ConstantExpr::getSub(RHS, C2));
3645     } else if (C.isZero()) {
3646       // Replace ((add A, B) != 0) with (A != -B) if A or B is
3647       // efficiently invertible, or if the add has just this one use.
3648       if (Value *NegVal = dyn_castNegVal(BOp1))
3649         return new ICmpInst(Pred, BOp0, NegVal);
3650       if (Value *NegVal = dyn_castNegVal(BOp0))
3651         return new ICmpInst(Pred, NegVal, BOp1);
3652       if (BO->hasOneUse()) {
3653         // (add nuw A, B) != 0 -> (or A, B) != 0
3654         if (match(BO, m_NUWAdd(m_Value(), m_Value()))) {
3655           Value *Or = Builder.CreateOr(BOp0, BOp1);
3656           return new ICmpInst(Pred, Or, Constant::getNullValue(BO->getType()));
3657         }
3658         Value *Neg = Builder.CreateNeg(BOp1);
