3670     } else if (C.isZero()) {
3671       // Replace ((xor A, B) != 0) with (A != B)
3672       return new ICmpInst(Pred, BOp0, BOp1);
3673     }
3674     break;
3675   case Instruction::Or: {
3676     const APInt *BOC;
