3678       // Comparing if all bits outside of a constant mask are set?
3679       // Replace (X | C) == -1 with (X & ~C) == ~C.
3680       // This removes the -1 constant.
3681       Constant *NotBOC = ConstantExpr::getNot(cast<Constant>(BOp1));
3682       Value *And = Builder.CreateAnd(BOp0, NotBOC);
3683       return new ICmpInst(Pred, And, NotBOC);
3684     }
3685     // (icmp eq (or (select cond, 0, NonZero), Other), 0)
3686     //  -> (and cond, (icmp eq Other, 0))
3687     // (icmp ne (or (select cond, NonZero, 0), Other), 0)
3688     //  -> (or cond, (icmp ne Other, 0))
3689     Value *Cond, *TV, *FV, *Other, *Sel;
3690     if (C.isZero() &&
3691         match(BO,
3692               m_OneUse(m_c_Or(m_CombineAnd(m_Value(Sel),
3693                                            m_Select(m_Value(Cond), m_Value(TV),
