3698       // Easy case is if eq/ne matches whether 0 is trueval/falseval.
3699       if (Pred == ICmpInst::ICMP_EQ
3700               ? (match(TV, m_Zero()) && isKnownNonZero(FV, Q))
3701               : (match(FV, m_Zero()) && isKnownNonZero(TV, Q))) {
