3706             Cond);
3707       }
3708       // Harder case is if eq/ne matches whether 0 is falseval/trueval. In this
3709       // case we need to invert the select condition so we need to be careful to
3710       // avoid creating extra instructions.
3711       // (icmp ne (or (select cond, 0, NonZero), Other), 0)
3712       //  -> (or (not cond), (icmp ne Other, 0))
3713       // (icmp eq (or (select cond, NonZero, 0), Other), 0)
3714       //  -> (and (not cond), (icmp eq Other, 0))
