3722                ? (match(FV, m_Zero()) && isKnownNonZero(TV, Q))
3723                : (match(TV, m_Zero()) && isKnownNonZero(FV, Q)))) {
3724         Value *NotCond = Builder.CreateNot(Cond);
3725         Value *Cmp = Builder.CreateICmp(
3726             Pred, Other, Constant::getNullValue(Other->getType()));
