3728             Pred == ICmpInst::ICMP_EQ ? Instruction::And : Instruction::Or, Cmp,
3729             NotCond);
3730       }
3731     }
3732     break;
3733   }
3734   case Instruction::UDiv:
3735   case Instruction::SDiv:
3736     if (BO->isExact()) {
3737       // div exact X, Y eq/ne 0 -> X eq/ne 0
3738       // div exact X, Y eq/ne 1 -> X eq/ne Y
