3769 static Instruction *foldCtpopPow2Test(ICmpInst &I, IntrinsicInst *CtpopLhs,
3770                                       const APInt &CRhs,
3771                                       InstCombiner::BuilderTy &Builder,
3772                                       const SimplifyQuery &Q) {
3773   assert(CtpopLhs->getIntrinsicID() == Intrinsic::ctpop &&
3774          "Non-ctpop intrin in ctpop fold");
