3778   // Power of 2 test:
3779   //    isPow2OrZero : ctpop(X) u< 2
3780   //    isPow2       : ctpop(X) == 1
3781   //    NotPow2OrZero: ctpop(X) u> 1
3782   //    NotPow2      : ctpop(X) != 1
3783   // If we know any bit of X can be folded to:
3784   //    IsPow2       : X & (~Bit) == 0
3785   //    NotPow2      : X & (~Bit) != 0
3786   const ICmpInst::Predicate Pred = I.getPredicate();
3787   if (((I.isEquality() || Pred == ICmpInst::ICMP_UGT) && CRhs == 1) ||
3788       (Pred == ICmpInst::ICMP_ULT && CRhs == 2)) {
3789     Value *Op = CtpopLhs->getArgOperand(0);
3790     KnownBits OpKnown = computeKnownBits(Op, Q.DL, Q.AC, Q.CxtI, Q.DT);
