3792     if (OpKnown.countMinPopulation() == 1) {
3793       Value *And = Builder.CreateAnd(
3794           Op, Constant::getIntegerValue(Op->getType(), ~(OpKnown.One)));
3795       return new ICmpInst(
3796           (Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_ULT)
3797               ? ICmpInst::ICMP_EQ
3798               : ICmpInst::ICMP_NE,
3799           And, Constant::getNullValue(Op->getType()));
3800     }
3801   }
3802 
3803   return nullptr;
3804 }
